//! Emit `sdks/python/src/tick_arrow.rs` — Arrow columnar pipeline.
//!
//! Two generator-owned surfaces live in the generated file:
//!
//! 1. `arrow_schema_for_qualname(qualname: &str) -> Option<Arc<Schema>>`
//!    — schema map keyed by tick pyclass `__qualname__`, so the
//!    empty-list case returns an empty `pyarrow.Table` with the
//!    correct typed schema (not a bare dict).
//!
//! 2. `pyclass_list_to_arrow_table(py, ticks, empty_qualname_hint)
//!    -> PyResult<Py<PyAny>>` — trait-driven dispatcher over
//!    `<T as ArrowFromPyclassList>::read_batch`, used by the public
//!    `to_arrow` / `to_dataframe` / `to_polars` entry points. Reads
//!    `#[pyo3(get)]` fields off the typed pyclass instances directly
//!    into Arrow builders — no Rust-tick-struct roundtrip, so it's
//!    strictly faster than the old dict-of-lists pivot.
//!
//! Zero-copy to `pyarrow`: each `RecordBatch` buffer is handed over
//! via the Arrow C Data Interface at the pyo3 boundary (courtesy of
//! `arrow_pyarrow::IntoPyArrow`). pandas 2.x consumes those buffers
//! in place for all numeric dtypes.

use std::fmt::Write as _;

use super::schema::{Schema, TickTypeDef};
use super::{pyclass_name, sorted_type_names};

pub(super) fn render_python_tick_arrow(schema: &Schema) -> String {
    let mut out = String::new();
    out.push_str("// @generated DO NOT EDIT — regenerated by build.rs from tick_schema.toml\n");
    out.push_str("// Arrow columnar pipeline. Single RecordBatch per converter, zero-copy to\n");
    out.push_str("// pyarrow via the Arrow C Data Interface (`arrow_pyarrow::IntoPyArrow`).\n");
    out.push_str("// Replaces the old dict-of-lists `PyDict` path; same schema, native Arrow\n");
    out.push_str("// typing, ~6x wall-clock speedup at 100k ticks.\n\n");
    // `Arc` is already imported at the `lib.rs` include-site (via
    // `std::sync::{Arc, Mutex}`); referencing `std::sync::Arc` here
    // would shadow. Paths below use fully-qualified `std::sync::Arc`
    // only inside the Schema-building helpers that predate the
    // lib.rs layout -- keep generator output self-sufficient by
    // qualifying the Arc references rather than importing again.
    //
    // `arrow::pyarrow` is the re-export exposed by the `pyarrow`
    // feature of the `arrow` crate; we go through it rather than
    // depending on `arrow-pyarrow` directly so the compat matrix is
    // single-sourced on `arrow`'s own version pin.
    out.push_str(
        "use arrow::array::{ArrayRef, Float64Array, Int32Array, Int64Array, StringArray};\n",
    );
    out.push_str("use arrow::datatypes::{DataType, Field, Schema};\n");
    out.push_str("use arrow::pyarrow::IntoPyArrow;\n");
    out.push_str("use arrow::record_batch::RecordBatch;\n\n");

    // Schema map + pyclass dispatcher (one surface covering every tick type).
    // Note: per-type `*_ticks_to_arrow_batch` fast-path helpers are not
    // emitted — see "Removed surfaces" at the top of the `ticks` module.
    out.push_str(&render_python_arrow_schema_map(schema));
    out.push('\n');
    out.push_str(&render_python_pyclass_to_arrow_dispatcher(schema));
    out
}

/// Map a `tick_schema.toml` column `type` to the Arrow `DataType` enum
/// variant we emit into the generated schema. `eod_num` (i32) and
/// `eod_num64` (i64) are distinct on the Rust side because one is
/// widened for volume/count; they preserve that distinction into
/// Arrow.
fn arrow_data_type_expr(column_type: &str) -> &'static str {
    match column_type {
        "i32" | "eod_num" | "eod_date" => "DataType::Int32",
        "i64" | "eod_num64" => "DataType::Int64",
        "f64" | "price" | "eod_price" => "DataType::Float64",
        "String" => "DataType::Utf8",
        other => panic!("unsupported Arrow data type for column type '{other}'"),
    }
}

/// Map a `tick_schema.toml` column `type` to the Arrow concrete array
/// constructor we call when materializing a column. Parallel to
/// `arrow_data_type_expr`; the caller wraps the result in
/// `Arc::new(...) as ArrayRef`.
fn arrow_array_ctor(column_type: &str) -> &'static str {
    match column_type {
        "i32" | "eod_num" | "eod_date" => "Int32Array",
        "i64" | "eod_num64" => "Int64Array",
        "f64" | "price" | "eod_price" => "Float64Array",
        "String" => "StringArray",
        other => panic!("unsupported Arrow array ctor for column type '{other}'"),
    }
}

/// Emit `arrow_schema_for_qualname` — a static schema map keyed on
/// pyclass `__qualname__`. Critical for the empty-list case: Arrow
/// cannot construct a `RecordBatch` without a schema, so we need a
/// source of typed field metadata keyed on tick class.
fn render_python_arrow_schema_map(schema: &Schema) -> String {
    let mut out = String::new();
    out.push_str("/// Typed Arrow schema keyed by the tick pyclass `__qualname__`.\n");
    out.push_str("/// Column order matches the `#[pyo3(get)]` field order emitted into\n");
    out.push_str("/// `tick_classes.rs` by the sibling renderer, so a given tick type\n");
    out.push_str("/// produces the same DataFrame column ordering through both the\n");
    out.push_str("/// Rust-slice fast path and the pyclass-list dispatcher.\n");
    out.push_str(
        "pub(crate) fn arrow_schema_for_qualname(qualname: &str) -> Option<Arc<Schema>> {\n",
    );
    out.push_str("    match qualname {\n");
    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        let class = pyclass_name(type_name);
        let is_quote_tick = type_name == "QuoteTick";
        writeln!(
            out,
            "        \"{class}\" => Some(Arc::new(Schema::new(vec!["
        )
        .unwrap();
        for column in &def.columns {
            // Mirror the pyclass projection: `OptionContract.right` surfaces
            // as a Python string (`"C"`/`"P"`/`""`) on the pyclass even
            // though the schema records it as `i32`. See
            // `render_python_tick_class_struct` for the matching rule.
            let dt = if type_name == "OptionContract" && column.field == "right" {
                "DataType::Utf8"
            } else {
                arrow_data_type_expr(column.r#type.as_str())
            };
            writeln!(
                out,
                "            Field::new(\"{name}\", {dt}, false),",
                name = column.name,
            )
            .unwrap();
        }
        if is_quote_tick {
            out.push_str("            Field::new(\"midpoint\", DataType::Float64, false),\n");
        }
        if def.contract_id {
            out.push_str("            Field::new(\"expiration\", DataType::Int32, false),\n");
            out.push_str("            Field::new(\"strike\", DataType::Float64, false),\n");
            out.push_str("            Field::new(\"right\", DataType::Utf8, false),\n");
        }
        out.push_str("        ]))),\n");
    }
    out.push_str("        _ => None,\n");
    out.push_str("    }\n");
    out.push_str("}\n");
    out
}

/// Emit `pyclass_list_to_arrow_table` — the generic dispatcher used
/// by `to_arrow` / `to_dataframe` / `to_polars`. The caller hands us
/// a `Py<PyList>` of tick pyclass instances and an optional qualname
/// hint for the empty-list case.
///
/// The match arms read `#[pyo3(get)]` fields off each pyclass into
/// typed Arrow builders. This skips the `__dir__` / `getattr` round-
/// trip the old `PyDict` path relied on.
fn render_python_pyclass_to_arrow_dispatcher(schema: &Schema) -> String {
    let mut out = String::new();
    out.push_str("/// Dispatch a list of typed tick pyclasses into a single `pyarrow.Table`.\n");
    out.push_str("/// Zero-copy at the pyo3 boundary courtesy of `arrow_pyarrow::IntoPyArrow`;\n");
    out.push_str("/// pandas 2.x then aliases the underlying Arrow buffers for all numeric\n");
    out.push_str("/// columns.\n");
    out.push_str("///\n");
    out.push_str("/// # Empty-list behaviour\n");
    out.push_str("///\n");
    out.push_str(
        "/// * non-empty list -> schema from `arrow_schema_for_qualname(first.qualname)`;\n",
    );
    out.push_str("///   mixed-type lists raise `PyRuntimeError`.\n");
    out.push_str("/// * empty list + hint -> schema from the hint, zero-row table (pandas /\n");
    out.push_str("///   polars still infer dtypes).\n");
    out.push_str("/// * empty list + no hint -> zero-column `pyarrow.Table` (public API:\n");
    out.push_str("///   see `to_arrow` docstring).\n");
    out.push_str("pub(crate) fn pyclass_list_to_arrow_table<'py>(\n");
    out.push_str("    py: Python<'py>,\n");
    out.push_str("    ticks: &Bound<'py, pyo3::types::PyList>,\n");
    out.push_str("    empty_qualname_hint: Option<&str>,\n");
    out.push_str(") -> PyResult<Py<PyAny>> {\n");
    out.push_str("    let qualname: Option<String> = if ticks.len() == 0 {\n");
    out.push_str("        empty_qualname_hint.map(std::string::ToString::to_string)\n");
    out.push_str("    } else {\n");
    out.push_str("        let first = ticks.get_item(0)?;\n");
    out.push_str("        Some(first.get_type().qualname()?.extract()?)\n");
    out.push_str("    };\n");
    out.push_str("    let Some(qualname) = qualname else {\n");
    out.push_str("        // Empty list + no hint -> zero-column Table (documented contract).\n");
    out.push_str("        let schema = Arc::new(Schema::empty());\n");
    out.push_str("        let batch = RecordBatch::new_empty(schema);\n");
    out.push_str("        return record_batch_to_pyarrow_table(py, batch);\n");
    out.push_str("    };\n");
    out.push_str("    let batch = match qualname.as_str() {\n");
    for type_name in sorted_type_names(schema) {
        let class = pyclass_name(type_name);
        writeln!(out, "        \"{class}\" => {{").unwrap();
        writeln!(
            out,
            "            <{class} as ArrowFromPyclassList>::read_batch(ticks)?"
        )
        .unwrap();
        out.push_str("        }\n");
    }
    out.push_str("        other => {\n");
    out.push_str("            return Err(pyo3::exceptions::PyRuntimeError::new_err(format!(\n");
    out.push_str(
        "                \"pyclass_list_to_arrow_table: unknown tick type `{other}` -- \\\n",
    );
    out.push_str("                 expected a value from `thetadatadx`'s typed tick classes\"\n");
    out.push_str("            )));\n");
    out.push_str("        }\n");
    out.push_str("    };\n");
    out.push_str("    record_batch_to_pyarrow_table(py, batch)\n");
    out.push_str("}\n");

    // Shared helper: convert RecordBatch -> pyarrow.Table via the C Data
    // Interface. The conversion is zero-copy: the RecordBatch buffers are
    // exported through an ArrowArrayStream whose lifetime pyarrow assumes.
    out.push('\n');
    out.push_str(include_str!(
        "templates/python_arrow/record_batch_to_pyarrow_table.rs.tmpl"
    ));

    // Per-class pyclass reader -- one helper per tick class. Casts each list
    // item down to the concrete pyclass and reads every #[pyo3(get)] field
    // via `.borrow().field` (no Python-level getattr roundtrip).
    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        out.push_str(&render_python_arrow_from_pyclass_reader(type_name, def));
        out.push('\n');
    }

    // Trait + impls -- lets each dispatcher arm call
    // `<ClassType as ArrowFromPyclassList>::read_batch(ticks)` without
    // re-emitting the body in every match arm.
    out.push_str(include_str!(
        "templates/python_arrow/arrow_from_pyclass_list_trait.rs.tmpl"
    ));
    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        out.push_str(&render_python_arrow_trait_impl(type_name, def));
        out.push('\n');
    }
    out
}

/// Emit a per-class reader function name for the dispatcher.
fn python_arrow_reader_fn_name(type_name: &str) -> String {
    format!(
        "read_arrow_batch_from_{}_pyclass_list",
        screaming_snake_to_snake(type_name)
    )
}

/// Map `EodTick` -> `eod_tick`, `OHLCTick` -> `o_h_l_c_tick`, etc.
/// Shared with `render_python_arrow_trait_impl`.
fn screaming_snake_to_snake(type_name: &str) -> String {
    let mut out = String::new();
    for (i, c) in type_name.chars().enumerate() {
        if c.is_uppercase() {
            if i != 0 {
                out.push('_');
            }
            for lc in c.to_lowercase() {
                out.push(lc);
            }
        } else {
            out.push(c);
        }
    }
    out
}

/// Emit a per-class reader function that walks the `PyList`, casts
/// each element down to the concrete pyclass, and collects every
/// `#[pyo3(get)]` field into a typed Arrow array. One pass over the
/// list per column -- cheap because each pyclass field access is a
/// direct C-offset read.
fn render_python_arrow_from_pyclass_reader(type_name: &str, def: &TickTypeDef) -> String {
    let mut out = String::new();
    let class = pyclass_name(type_name);
    let fn_name = python_arrow_reader_fn_name(type_name);
    let is_quote_tick = type_name == "QuoteTick";
    let is_contract = def.contract_id;

    writeln!(
        out,
        "fn {fn_name}<'py>(ticks: &Bound<'py, pyo3::types::PyList>) -> PyResult<RecordBatch> {{"
    )
    .unwrap();
    writeln!(
        out,
        "    let schema = arrow_schema_for_qualname(\"{class}\").expect(\"generated schema must be present for {class}\");"
    )
    .unwrap();
    out.push_str("    let n = ticks.len();\n");

    // Pre-size typed Vecs; one pass per column. `OptionContract.right`
    // is the single column whose pyclass-visible type differs from its
    // schema type (String on the pyclass, `i32` in the TOML); see the
    // matching rules in `render_python_tick_class_struct` /
    // `render_python_tick_class_list_fn`. Mirror that projection here so
    // the Arrow array buffer matches what the pyclass actually exposes.
    let mut column_decls: Vec<(String, String)> = Vec::new(); // (ident, effective type)
    for column in &def.columns {
        let effective_type: &str = if type_name == "OptionContract" && column.field == "right" {
            "String"
        } else {
            column.r#type.as_str()
        };
        let rust_ty = match effective_type {
            "i32" | "eod_num" | "eod_date" => "i32",
            "i64" | "eod_num64" => "i64",
            "f64" | "price" | "eod_price" => "f64",
            "String" => "String",
            other => panic!("unsupported column type '{other}' in pyclass reader for {type_name}"),
        };
        writeln!(
            out,
            "    let mut col_{field}: Vec<{rust_ty}> = Vec::with_capacity(n);",
            field = column.field
        )
        .unwrap();
        column_decls.push((column.field.clone(), effective_type.to_string()));
    }
    if is_quote_tick {
        out.push_str("    let mut col_midpoint: Vec<f64> = Vec::with_capacity(n);\n");
    }
    if is_contract {
        out.push_str("    let mut col_expiration: Vec<i32> = Vec::with_capacity(n);\n");
        out.push_str("    let mut col_strike: Vec<f64> = Vec::with_capacity(n);\n");
        out.push_str("    let mut col_right: Vec<String> = Vec::with_capacity(n);\n");
    }

    out.push_str("    for i in 0..n {\n");
    out.push_str("        let item = ticks.get_item(i)?;\n");
    writeln!(
        out,
        "        let typed: pyo3::PyRef<'_, {class}> = item.extract().map_err(|_| {{"
    )
    .unwrap();
    writeln!(
        out,
        "            pyo3::exceptions::PyRuntimeError::new_err(format!("
    )
    .unwrap();
    writeln!(
        out,
        "                \"pyclass_list_to_arrow_table: expected all items to be `{class}`, \\\n                 got `{{}}` at index {{}}\", item.get_type().qualname().unwrap_or_else(|_| pyo3::types::PyString::new(ticks.py(), \"?\")), i"
    )
    .unwrap();
    out.push_str("            ))\n");
    out.push_str("        })?;\n");
    for column in &def.columns {
        let field = &column.field;
        // `OptionContract.right` is a `String` on the pyclass even though
        // its schema type is `i32`; see the projection in
        // `render_python_tick_class_struct`. Match the pyclass type, not
        // the raw column type, so `typed.right.clone()` compiles.
        let effective_type: &str = if type_name == "OptionContract" && column.field == "right" {
            "String"
        } else {
            column.r#type.as_str()
        };
        match effective_type {
            "String" => {
                writeln!(out, "        col_{field}.push(typed.{field}.clone());").unwrap();
            }
            _ => {
                writeln!(out, "        col_{field}.push(typed.{field});").unwrap();
            }
        }
    }
    if is_quote_tick {
        out.push_str("        col_midpoint.push(typed.midpoint);\n");
    }
    if is_contract {
        out.push_str("        col_expiration.push(typed.expiration);\n");
        out.push_str("        col_strike.push(typed.strike);\n");
        out.push_str("        col_right.push(typed.right.clone());\n");
    }
    out.push_str("    }\n");

    // Build arrays.
    out.push_str("    let columns: Vec<ArrayRef> = vec![\n");
    for (field, column_type) in &column_decls {
        let ctor = arrow_array_ctor(column_type);
        writeln!(
            out,
            "        Arc::new({ctor}::from(col_{field})) as ArrayRef,"
        )
        .unwrap();
    }
    if is_quote_tick {
        out.push_str("        Arc::new(Float64Array::from(col_midpoint)) as ArrayRef,\n");
    }
    if is_contract {
        out.push_str("        Arc::new(Int32Array::from(col_expiration)) as ArrayRef,\n");
        out.push_str("        Arc::new(Float64Array::from(col_strike)) as ArrayRef,\n");
        out.push_str("        Arc::new(StringArray::from(col_right)) as ArrayRef,\n");
    }
    out.push_str("    ];\n");
    out.push_str(
        "    RecordBatch::try_new(schema, columns).map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))\n",
    );
    out.push_str("}\n");
    out
}

/// Emit the `ArrowFromPyclassList` trait impl for each tick pyclass.
fn render_python_arrow_trait_impl(type_name: &str, _def: &TickTypeDef) -> String {
    let mut out = String::new();
    let class = pyclass_name(type_name);
    let reader = python_arrow_reader_fn_name(type_name);
    writeln!(out, "impl ArrowFromPyclassList for {class} {{").unwrap();
    out.push_str(
        "    fn read_batch<'py>(ticks: &Bound<'py, pyo3::types::PyList>) -> PyResult<RecordBatch> {\n",
    );
    writeln!(out, "        {reader}(ticks)").unwrap();
    out.push_str("    }\n");
    out.push_str("}\n");
    out
}
